// Data/KmgDbContext.cs
using Microsoft.EntityFrameworkCore;
using KmgAssets.Models;

namespace KmgAssets.Data;

public sealed class KmgDbContext : DbContext
{
    public DbSet<Asset> Assets => Set<Asset>();
    public DbSet<Department> Departments => Set<Department>();

    private readonly string _connectionString;
    public KmgDbContext(string connectionString) => _connectionString = connectionString;

    protected override void OnConfiguring(DbContextOptionsBuilder options)
        => options.UseSqlServer(_connectionString);

    protected override void OnModelCreating(ModelBuilder b)
    {
        b.Entity<Asset>(e =>
        {
            e.ToTable("Assets", "dbo");
            e.Property(x => x.Name).HasMaxLength(100).IsRequired();
            e.Property(x => x.Status).HasMaxLength(20).IsRequired();
            e.HasOne(x => x.Department)
                .WithMany(d => d.Assets)
                .HasForeignKey(x => x.DepartmentId)
                .OnDelete(DeleteBehavior.Restrict);
        });

        b.Entity<Department>(e =>
        {
            e.ToTable("Departments", "dbo");
            e.Property(x => x.Name).HasMaxLength(50).IsRequired();
        });
    }
}

using Microsoft.EntityFrameworkCore;
using KmgAssets.Data;
using KmgAssets.Models;

namespace KmgAssets.Services;

public sealed class AssetRepository
{
    private readonly Func<KmgDbContext> _dbFactory;
    public AssetRepository(Func<KmgDbContext> dbFactory) => _dbFactory = dbFactory;

    public async Task<List<Asset>> GetAllAsync(string? search, CancellationToken ct = default)
    {
        using var db = _dbFactory();
        var query = db.Assets
            .AsNoTracking()
            .Include(a => a.Department)
            .OrderBy(a => a.Name);

        if (!string.IsNullOrWhiteSpace(search))
            return await query
                .Where(a => EF.Functions.Like(a.Name, $"%{search}%"))
                .ToListAsync(ct);

        return await query.ToListAsync(ct);
    }

    public async Task<Asset?> GetByIdAsync(int id, CancellationToken ct = default)
    {
        using var db = _dbFactory();
        return await db.Assets
            .AsNoTracking()
            .Include(a => a.Department)
            .FirstOrDefaultAsync(a => a.Id == id, ct);
    }

    public async Task<int> AddAsync(Asset asset, CancellationToken ct = default)
    {
        using var db = _dbFactory();
        db.Assets.Add(asset);
        await db.SaveChangesAsync(ct);
        return asset.Id;
    }

    public async Task UpdateAsync(Asset asset, CancellationToken ct = default)
    {
        using var db = _dbFactory();
        db.Assets.Update(asset);
        await db.SaveChangesAsync(ct);
    }

    public async Task DeleteAsync(int id, CancellationToken ct = default)
    {
        using var db = _dbFactory();
        var a = await db.Assets.FirstOrDefaultAsync(x => x.Id == id, ct);
        if (a is null) return;
        db.Assets.Remove(a);
        await db.SaveChangesAsync(ct);
    }
}

// MauiProgram.cs
builder.Services.AddSingleton<Func<KmgDbContext>>(sp =>
    () => new KmgDbContext(
        Preferences.Default.Get("DbConnectionString",
            "Server=localhost\\SQLEXPRESS;Database=KmgAssets;Integrated Security=True;TrustServerCertificate=True;")));
builder.Services.AddSingleton<AssetRepository>();
